import rclpy
from rclpy.node import Node
from std_msgs.msg import Float32MultiArray
from dynamixel_sdk import *
import ctypes
import math
import time

def cast_to_int32(value):
    """Converts unsigned raw bytes from Dynamixel registers to signed 32-bit integers."""
    return ctypes.c_int32(int(value)).value

class Dynamixel_XW430_T200_interface(Node):
    def __init__(self):
        super().__init__('servo_actuator')
        
        self.is_configured = False
        self.current_baudrate = -1

        # --- Declare Parameters ---
        self.declare_parameter('baudrate', 1000000)  # Changed default to 1M (more common)
        self.declare_parameter('control_loop_rate', 0.001)
        self.declare_parameter('current_limit', 800)

        # Get initial values
        self.current_baudrate = self.get_parameter('baudrate').value
        loop_rate = self.get_parameter('control_loop_rate').value
        
        # --- Hardware Communication Layer ---
        self.port = PortHandler('/dev/ttyUSB0')
        self.packet_handler = PacketHandler(2.0)
        
        if not self.port.openPort() or not self.port.setBaudRate(self.current_baudrate):
            self.get_logger().error(f"Hardware Link Failed at {self.current_baudrate} bps!")

        # --- Control Table Addresses ---
        self.ADDR_BAUD_RATE    = 8
        self.ADDR_TORQUE       = 64
        self.ADDR_MODE         = 11
        self.ADDR_GOAL_VEL     = 104
        self.ADDR_GOAL_POS     = 116
        self.ADDR_PRESENT_DATA = 126
        self.ADDR_CURRENT_LIMIT = 38

        # --- Unit Conversion Constants ---
        self.TICKS_PER_RAD = 4096.0 / (2.0 * math.pi)
        self.RADS_TO_VEL_UNIT = 1.0 / (0.229 * (2.0 * math.pi / 60.0))
        self.VEL_UNIT_TO_RADS = 0.229 * (2.0 * math.pi / 60.0)

        # --- Internal State ---
        self.latest_command = None 
        self.active_ids = []
        self.id_modes = {}      
        self.is_configuring = False 

        # --- ROS2 Interfaces (Hardcoded QoS depth 1) ---
        self.feedback_pub = self.create_publisher(Float32MultiArray, 'joint_feedback', 1)
        self.joint_sub = self.create_subscription(Float32MultiArray, 'joint_cmd', self.ros_cb, 1)

        self.control_timer = self.create_timer(loop_rate, self.hardware_loop)
        self.get_logger().info(f"Interface Online: {self.current_baudrate} bps default.")

    def ros_cb(self, msg):
        try:
            n = len(msg.data) // 3
            if n == 0: 
                return
            self.latest_command = (
                [int(round(x)) for x in msg.data[0:n]],
                [int(round(x)) for x in msg.data[n:2*n]],
                [float(x) for x in msg.data[2*n:3*n]]
            )
        except Exception as e:
            self.get_logger().warn(f"Invalid joint command: {e}")

    def hardware_loop(self):
        if self.latest_command is None or self.is_configuring: 
            return
        
        ids, modes, goals = self.latest_command
        new_baud = self.get_parameter('baudrate').value

        # Reconfigure if IDs change, modes change, or baudrate parameter is updated
        if not self.is_configured or self.check_reconfig_needed(ids, modes) or new_baud != self.current_baudrate:
            self.setup_sync_io(ids, modes, new_baud)
            return

        try:
            # PHASE 1: WRITE
            for i, sid in enumerate(ids):
                if sid not in self.active_ids: 
                    continue
                mode, goal = modes[i], goals[i]
                raw_val = int(goal * self.TICKS_PER_RAD) if mode == 3 else int(goal * self.RADS_TO_VEL_UNIT)
                byte_array = [DXL_LOBYTE(DXL_LOWORD(raw_val)), DXL_HIBYTE(DXL_LOWORD(raw_val)),
                             DXL_LOBYTE(DXL_HIWORD(raw_val)), DXL_HIBYTE(DXL_HIWORD(raw_val))]
                
                target_sync = self.pos_sync if mode == 3 else self.vel_sync
                target_sync.addParam(sid, byte_array)

            self.pos_sync.txPacket()
            self.pos_sync.clearParam()
            self.vel_sync.txPacket()
            self.vel_sync.clearParam()

            # PHASE 2: READ
            if self.feedback_read_sync.txRxPacket() == COMM_SUCCESS:
                fb_data = []
                for sid in self.active_ids:
                    if self.feedback_read_sync.isAvailable(sid, self.ADDR_PRESENT_DATA, 20):
                        curr = self.feedback_read_sync.getData(sid, self.ADDR_PRESENT_DATA, 2)
                        vel  = self.feedback_read_sync.getData(sid, self.ADDR_PRESENT_DATA + 2, 4)
                        pos  = self.feedback_read_sync.getData(sid, self.ADDR_PRESENT_DATA + 6, 4)
                        volt = self.feedback_read_sync.getData(sid, self.ADDR_PRESENT_DATA + 18, 2)
                        
                        fb_data.extend([
                            float(sid), float(self.id_modes[sid]),
                            float(cast_to_int32(pos)) / self.TICKS_PER_RAD,
                            float(cast_to_int32(vel)) * self.VEL_UNIT_TO_RADS,
                            float(ctypes.c_int16(curr).value) * 0.00269,
                            float(volt) * 0.1
                        ])
                
                if fb_data:
                    msg = Float32MultiArray()
                    msg.data = fb_data
                    self.feedback_pub.publish(msg)
        except Exception as e:
            self.get_logger().error(f"Hardware loop error: {e}")

    def check_reconfig_needed(self, ids, modes):
        if set(ids) != set(self.active_ids):
            return True
        for i, sid in enumerate(ids):
            if sid in self.id_modes and self.id_modes[sid] != modes[i]:
                return True
        return False

    def setup_sync_io(self, ids, modes, requested_baud):
        self.is_configuring = True
        
        # Validate inputs first
        if len(ids) != len(modes):
            self.get_logger().error(f"Length mismatch: ids={len(ids)}, modes={len(modes)}")
            self.is_configuring = False
            return
            
        # Ensure modes are valid bytes (0-255)
        for i, mode in enumerate(modes):
            if not (0 <= mode <= 255):
                self.get_logger().error(f"Invalid mode value: modes[{i}]={mode} (must be 0-255)")
                self.is_configuring = False
                return
        
        self.get_logger().info(f"Configuring IDs {ids}, modes {modes} @ {requested_baud} bps")
    
        # --- Complete Baudrate Mapping from Documentation ---
        BAUD_MAP = {
            9600: 0, 57600: 1, 115200: 2, 1000000: 3,
            2000000: 4, 3000000: 5, 4000000: 6, 4500000: 7
        }
        
        new_baud_reg = BAUD_MAP.get(requested_baud, 3)  # Default to 1M
        limit = self.get_parameter('current_limit').value

        # Step 1: Handle baudrate change FIRST (if needed)
        if requested_baud != self.current_baudrate:
            self.get_logger().info(f"Changing baudrate: {self.current_baudrate} -> {requested_baud}")
            for sid in ids:
                try:
                    # Torque OFF to change baudrate
                    self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_TORQUE, 0)
                    time.sleep(0.01)
                    # Tell servo to change its baudrate
                    self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_BAUD_RATE, new_baud_reg)
                    time.sleep(0.01)
                except Exception as e:
                    self.get_logger().error(f"Baudrate change failed for servo {sid}: {e}")
            
            # NOW match the U2D2 port to the new servo speed
            if self.port.setBaudRate(requested_baud):
                self.current_baudrate = requested_baud
                self.get_logger().info(f"U2D2 Port Baudrate updated to {requested_baud}")
                time.sleep(0.1)  # Let the port stabilize

        # Step 2: Configure modes and limits (now at correct baudrate)
        for sid in ids:
            idx = ids.index(sid)
            try:
                # Torque OFF (in case we skipped baudrate change)
                self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_TORQUE, 0)
                time.sleep(0.01)
                
                # Set current limit and operating mode
                self.packet_handler.write2ByteTxRx(self.port, sid, self.ADDR_CURRENT_LIMIT, limit)
                
                # Ensure mode is an int in valid range
                mode_value = int(modes[idx])
                if not (0 <= mode_value <= 16):  # Dynamixel modes are 0-16
                    self.get_logger().warn(f"Mode {mode_value} for servo {sid} unusual, clamping")
                    mode_value = max(0, min(16, mode_value))
                
                self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_MODE, mode_value)
                self.id_modes[sid] = mode_value
                self.get_logger().info(f"Servo {sid} configured: mode={mode_value}, limit={limit}mA")
                
            except Exception as e:
                self.get_logger().error(f"Config failed for servo {sid}: {e}")

        # Step 3: Re-initialize Sync Handlers
        self.active_ids = ids
        self.pos_sync = GroupSyncWrite(self.port, self.packet_handler, self.ADDR_GOAL_POS, 4)
        self.vel_sync = GroupSyncWrite(self.port, self.packet_handler, self.ADDR_GOAL_VEL, 4)
        self.feedback_read_sync = GroupSyncRead(self.port, self.packet_handler, self.ADDR_PRESENT_DATA, 20)
        
        # Step 4: Enable torque and add read parameters
        for sid in ids:
            try:
                self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_TORQUE, 1)
                self.feedback_read_sync.addParam(sid)
            except Exception as e:
                self.get_logger().error(f"Torque enable failed for servo {sid}: {e}")

        self.is_configured = True
        self.is_configuring = False
        self.get_logger().info("Hardware configuration complete.")

    def destroy_node(self):
        for sid in self.active_ids:
            try: 
                self.packet_handler.write1ByteTxRx(self.port, sid, self.ADDR_TORQUE, 0)
            except: 
                pass
        self.port.closePort()
        super().destroy_node()

def main(args=None):
    rclpy.init(args=args)
    node = Dynamixel_XW430_T200_interface()
    try: 
        rclpy.spin(node)
    except KeyboardInterrupt: 
        pass
    finally:
        node.destroy_node()
        rclpy.shutdown()

if __name__ == '__main__':
    main()